'use strict';

const {stripCookieString} = require('../middleware/strip-client-cookies');
const sessionCookieProvider = require('../middleware/session-cookie-provider');
const {setBackendCookiesEnabled} = require('./cookie-utils');

exports.processOutgoingCookies = function (req, headers, cookieName, cb) {
  if (!req.session || !req.internalUrl) {
    return cb();
  }

  if (!setBackendCookiesEnabled(req)) {
    var stripped = stripCookieString(req, headers.cookie, cookieName);
    if (stripped === null) {
      delete headers.cookie;
    } else {
      headers.cookie = stripped;
    }
  }

  if (!req.session._cookieJar) {
    return cb();
  }

  sessionCookieProvider(req, function (err, cookies) {
    if (err) {
      return cb(err);
    }
    if (cookies) {
      headers.cookie = headers.cookie ? headers.cookie + '; ' + cookies : cookies;
    }
    cb();
  });
};
